    for (long num : nums) {
        sum += num;
    }

    // The minimal possible sum is the remainder of the total sum divided by k
    // If the remainder is zero, then the entire array can be deleted, leaving sum zero
    // Otherwise, the minimal sum is the remainder
    long remainder = sum % k;
